@import '../../utils/focus-ring.css';

:host {
  display: block;
}

.tab-list {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
  position: relative;
  width: max-content;
  max-width: 100%;
  height: var(--dimension-size-400);
  padding: calc(var(--dimension-space-050) - var(--dimension-stroke-width-012));
  background-color: var(--color-background-secondary);
  border: var(--dimension-stroke-width-012) solid var(--color-border-tertiary);
  border-radius: var(--dimension-radius-half);
  box-sizing: border-box;
}

/* Vertical orientation */
.tab-list--vertical {
  flex-direction: column;
  align-items: stretch;
}

.tab {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--dimension-space-050);
  padding: var(--dimension-space-050);
  background-color: transparent;
  border: var(--dimension-stroke-width-012) solid transparent;
  border-radius: var(--dimension-radius-half);
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
  color: var(--color-foreground-secondary);
  position: relative;
  /* Only transition color — hover bg is instant (see ::after below) */
  transition: color var(--effect-motion-short-2);
  flex-shrink: 0;
  height: var(--dimension-size-300);
  min-width: var(--dimension-size-400);
  box-sizing: border-box;
  --_hover-bg: var(--color-interaction-hover);
  --_pressed-bg: var(--color-interaction-pressed);
  --_dot: var(--color-foreground-bold-brand);
  --_dot-ring: var(--color-background-secondary);
}

/* Interaction layer — same pattern as PanelNav */
.tab::after {
  content: '';
  position: absolute;
  inset: calc(var(--dimension-stroke-width-012) * -1);
  border-radius: inherit;
  background: transparent;
  pointer-events: none;
  transition: none;
}

.tab:hover::after  { background: var(--_hover-bg);   transition: none; }
.tab:active::after { background: var(--_pressed-bg);  transition: none; }

.tab--selected {
  color: var(--color-foreground-primary);
  background-color: var(--color-background-primary);
  border-color: var(--color-border-tertiary);
}

.tab:disabled,
.tab[aria-disabled="true"] {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

/* Vertical tabs read as a list — left-align the label */
.tab-list--vertical .tab { justify-content: flex-start; }

/* Label — dot anchors top-right like BarNav action icon zone */
.tab__label {
  position: relative;
  display: inline-flex;
  align-items: center;
  padding: 0 var(--dimension-space-025);
  white-space: nowrap;
}

/* Clearance for top-right dot — slightly less than space-025 + space-075 */
.tab__label--dot {
  padding-right: calc(var(--dimension-space-025) + var(--dimension-space-050));
}

/* Notification dot — top-right corner of the label zone */
.tab__dot {
  position: absolute;
  top: 0;
  right: 0;
  pointer-events: none;
}

/* Background context */
.on-medium {
  --_hover-bg: var(--color-interaction-on-medium-background-hover);
  --_pressed-bg: var(--color-interaction-on-medium-background-pressed);
  --_dot-ring: var(--color-background-medium-neutral);
  --ds-focus-ring-color: var(--color-interaction-on-medium-background-focus);
}

.on-bold {
  --_hover-bg: var(--color-interaction-on-bold-background-hover);
  --_pressed-bg: var(--color-interaction-on-bold-background-pressed);
  --_dot-ring: var(--color-background-bold-neutral);
  --ds-focus-ring-color: var(--color-interaction-on-bold-background-focus);
  color: var(--color-foreground-on-bold-background-secondary);
}

.on-bold.tab--selected { color: var(--color-foreground-on-bold-background-primary); }

.on-strong {
  --_hover-bg: var(--color-interaction-on-strong-background-hover);
  --_pressed-bg: var(--color-interaction-on-strong-background-pressed);
  --_dot-ring: var(--color-background-strong-neutral);
  --ds-focus-ring-color: var(--color-interaction-on-strong-background-focus);
  color: var(--color-foreground-on-bold-background-secondary);
}

.on-strong.tab--selected { color: var(--color-foreground-on-bold-background-primary); }

.on-always-dark {
  --_hover-bg: var(--color-always-dark-interaction-hover);
  --_pressed-bg: var(--color-always-dark-interaction-pressed);
  --_dot-ring: var(--color-always-dark-background);
  --ds-focus-ring-color: var(--color-always-dark-interaction-focus);
  color: var(--color-always-dark-foreground-secondary);
}

.on-always-dark.tab--selected { color: var(--color-always-dark-foreground-primary); }

/* In-tablist visual group separator — not focusable, skipped by keyboard nav.
   Pill tabs use text-body-small (line-height sm / 16px). Width is only the line;
   `.tab-list` gap supplies the same spacing as between tabs. */
.tab-divider {
  display: flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  width: var(--dimension-stroke-width-012);
  align-self: center;
  padding: 0;
  flex-shrink: 0;
  pointer-events: none;
}

.tab-divider__line {
  width: var(--dimension-stroke-width-012);
  height: var(--typography-lineheight-sm);
  flex-shrink: 0;
  background-color: var(--color-border-secondary);
}

.tab-divider--vertical {
  width: auto;
  height: var(--dimension-stroke-width-012);
  align-self: stretch;
  padding: 0;
}

.tab-divider--vertical .tab-divider__line {
  width: auto;
  height: var(--dimension-stroke-width-012);
  align-self: stretch;
}

import { Component, Prop, Event, EventEmitter, Element, Listen, Watch, h, Host } from '@stencil/core';
import {
  getSelectableTabs,
  isTabDivider,
  type TabItem,
  type TabItemTab,
} from './tab-item-utils';

export type TabBackground = 'faint' | 'medium' | 'bold' | 'strong' | 'always-dark';

@Component({
  tag: 'ds-tab-group',
  styleUrl: 'TabGroup.css',
  scoped: true,
})
export class TabGroup {
  @Element() el!: HTMLElement;

  @Prop({ mutable: true }) value: string = '';
  @Prop() tabs: TabItem[] = [];
  @Prop() background: TabBackground | undefined;
  @Prop({ attribute: 'aria-label' }) ariaLabel: string | undefined;
  @Prop({ attribute: 'aria-labelledby' }) ariaLabelledby: string | undefined;
  @Prop() orientation: 'horizontal' | 'vertical' = 'horizontal';

  @Event() dsChange!: EventEmitter<string>;

  private get selectableTabs(): TabItemTab[] {
    return getSelectableTabs(this.tabs);
  }

  private selectTab(id: string, options?: { focus?: boolean }) {
    this.value = id;
    this.dsChange.emit(id);
    if (options?.focus !== false) {
      this.focusTab(id);
    }
  }

  private focusTab(id: string) {
    const btn = this.el.querySelector(`[data-tab-id="${id}"]`) as HTMLElement | null;
    btn?.focus({ preventScroll: true });
  }

  /** Keep focus on the selected tab when value changes externally (e.g. BarNav menu). */
  @Watch('value')
  onValueChange(next: string, prev: string | undefined) {
    if (prev === undefined || next === prev) return;

    requestAnimationFrame(() => {
      const active = document.activeElement as HTMLElement | null;
      if (!active || !this.el.contains(active)) return;

      const activeId = active.getAttribute('data-tab-id');
      if (activeId === next) return;

      const nextTab = this.el.querySelector(`[data-tab-id="${next}"]`) as HTMLElement | null;
      if (nextTab) {
        nextTab.focus({ preventScroll: true });
      } else {
        active.blur();
      }
    });
  }

  /**
   * Find the next non-disabled tab index relative to `from`, stepping by `step`.
   * Returns `from` unchanged if no other enabled tab exists.
   */
  private findEnabled(from: number, step: 1 | -1): number {
    const tabs = this.selectableTabs;
    const len = tabs.length;
    for (let n = 0; n < len; n++) {
      const i = (from + step * (n + 1) + len * (n + 1)) % len;
      if (!tabs[i]?.disabled) return i;
    }
    return from;
  }

  @Listen('keydown')
  handleKeyDown(e: KeyboardEvent) {
    const tabs = this.selectableTabs;
    if (!tabs.length) return;

    const currentIdx = tabs.findIndex(t => t.id === this.value);
    const isVertical = this.orientation === 'vertical';

    let nextIdx: number | null = null;

    if (!isVertical) {
      if (e.key === 'ArrowRight') {
        nextIdx = this.findEnabled(currentIdx, 1);
      } else if (e.key === 'ArrowLeft') {
        nextIdx = this.findEnabled(currentIdx, -1);
      }
    } else {
      if (e.key === 'ArrowDown') {
        nextIdx = this.findEnabled(currentIdx, 1);
      } else if (e.key === 'ArrowUp') {
        nextIdx = this.findEnabled(currentIdx, -1);
      }
    }

    if (e.key === 'Home') {
      const first = tabs.findIndex(t => !t.disabled);
      nextIdx = first === -1 ? null : first;
    } else if (e.key === 'End') {
      const lastEnabled = [...tabs].reverse().findIndex(t => !t.disabled);
      nextIdx = lastEnabled === -1 ? null : tabs.length - 1 - lastEnabled;
    }

    if (nextIdx !== null) {
      e.preventDefault();
      const next = tabs[nextIdx];
      this.selectTab(next.id);
    }
  }

  private getBgClass(): string {
    if (!this.background || this.background === 'faint') return '';
    if (this.background === 'always-dark') return 'on-always-dark';
    return `on-${this.background}`;
  }

  render() {
    const bgClass = this.getBgClass();
    const isVertical = this.orientation === 'vertical';

    return (
      <Host class="tab-group-host">
        <div
          role="tablist"
          class={{ 'tab-list': true, 'tab-list--vertical': isVertical }}
          aria-label={this.ariaLabel}
          aria-labelledby={this.ariaLabelledby}
          aria-orientation={isVertical ? 'vertical' : undefined}
        >
          {this.tabs.map((tab, index) => {
            if (isTabDivider(tab)) {
              return (
                <div
                  key={`divider-${index}`}
                  class={{
                    'tab-divider': true,
                    'tab-divider--vertical': isVertical,
                  }}
                  aria-hidden="true"
                >
                  <div class="tab-divider__line" />
                </div>
              );
            }

            const isSelected = tab.id === this.value;
            return (
              <button
                key={tab.id}
                type="button"
                role="tab"
                data-tab-id={tab.id}
                class={{
                  tab: true,
                  'tab--selected': isSelected,
                  'ds-focus-ring-inset': true,
                  [bgClass]: !!bgClass,
                }}
                aria-selected={isSelected}
                aria-disabled={tab.disabled || undefined}
                aria-controls={tab.panelId ?? undefined}
                disabled={tab.disabled}
                tabIndex={isSelected ? 0 : -1}
                onClick={() => !tab.disabled && this.selectTab(tab.id)}
              >
                <span class={{
                  tab__label: true,
                  'tab__label--dot': !!tab.dot,
                  [isSelected ? 'text-body-small-emphasis' : 'text-body-small']: true,
                }}>
                  {tab.label}
                  {tab.dot && (
                    <ds-badge
                      class="tab__dot"
                      variant="dot"
                      background="var(--_dot-ring)"
                      label=""
                      aria-hidden="true"
                    />
                  )}
                </span>
              </button>
            );
          })}
        </div>
      </Host>
    );
  }
}

export interface TabItemDivider {
  type: 'divider';
}

export interface TabItemTab {
  id: string;
  label: string;
  disabled?: boolean;
  /** id of the tabpanel this tab controls */
  panelId?: string;
  /** Show a notification dot (brand) on the tab — no count, matching panel-nav. */
  dot?: boolean;
}

export type TabItem = TabItemTab | TabItemDivider;

export function isTabDivider(item: TabItem): item is TabItemDivider {
  return 'type' in item && item.type === 'divider';
}

/** Tab entries that participate in selection, keyboard nav, and URL matching. */
export function getSelectableTabs(tabs: TabItem[]): TabItemTab[] {
  return tabs.filter((t): t is TabItemTab => !isTabDivider(t));
}
